from string_utils.manipulation import prettify

def test__prettify_mutant_error():
    """
    Test the prettify function to see if it raises a SyntaxError due to modified code in __ensure_left_space_only.
    The mutant contains an invalid operation that should cause an error.
    """
    try:
        output = prettify("  test string  ")
        print(f"output = {output}")
    except SyntaxError as e:
        print(f"SyntaxError encountered: {e}")
    except Exception as e:
        print(f"Other Exception encountered: {e}")
